<?php
namespace App\Domain\Admin\Content;use App\Domain\Equipment\EquipmentType;use App\Domain\Equipment\EquippableItemValidator;use App\Domain\Inventory\ItemClassification;use App\Domain\WorldCatalog\CatalogStatus;use App\Domain\WorldCatalog\ItemRarity;use App\Domain\WorldCatalog\ItemType;use App\Domain\WorldCatalog\ZoneType;use App\Models\Item;use App\Models\Monster;use App\Models\MonsterLootEntry;use App\Models\Region;use App\Models\Zone;use InvalidArgumentException;
final class ContentAdminReadService{private $classification;private $equippable;public function __construct(ItemClassification $classification,EquippableItemValidator $equippable){$this->classification=$classification;$this->equippable=$equippable;}public function itemOptions(){return['item_types'=>ItemType::values(),'equipment_types'=>EquipmentType::all(),'rarities'=>ItemRarity::values(),'statuses'=>CatalogStatus::values()];}public function zoneOptions(){return['regions'=>Region::with('world')->orderBy('world_id')->orderBy('name')->get(),'zone_types'=>ZoneType::values(),'statuses'=>CatalogStatus::values()];}public function statuses(){return CatalogStatus::values();}public function items(){$p=Item::orderBy('name')->paginate(25);$p->setCollection($p->getCollection()->map(function($item){return$this->itemData($item);}));return$p;}public function item(Item $item){return$this->itemData($item);}private function itemData(Item $item){try{$classification=$this->classification->classify($item);$this->equippable->equipmentType($item);$coherent=true;}catch(InvalidArgumentException $e){$classification='incoherent';$coherent=false;}return['model'=>$item,'classification'=>$classification,'coherent'=>$coherent,'bonuses'=>['max_health_bonus'=>$item->max_health_bonus,'attack_bonus'=>$item->attack_bonus,'defense_bonus'=>$item->defense_bonus,'accuracy_bonus'=>$item->accuracy_bonus,'evasion_bonus'=>$item->evasion_bonus,'critical_chance_bonus'=>$item->critical_chance_bonus,'attack_speed_bonus'=>$item->attack_speed_bonus]];}public function monsters(){return Monster::with(['zones.region.world','lootEntries.item'])->orderBy('name')->paginate(25);}public function monster(Monster $monster){return$monster->load(['zones.region.world','lootEntries.item']);}public function zones(){return Zone::with('region.world')->orderBy('region_id')->orderBy('name')->paginate(25);}public function zone(Zone $zone){return$zone->load(['region.world','monsters']);}public function loot(){return MonsterLootEntry::with(['monster','item'])->orderBy('monster_id')->orderBy('sort_order')->paginate(25);}public function percent($basisPoints){return round(((int)$basisPoints)/100,2);}}
